class Solution:
    def executeInstructions(self, n, startPos, s):
        m = len(s)
        dr = {'L': 0, 'R': 0, 'U': -1, 'D': 1}
        dc = {'L': -1, 'R': 1, 'U': 0, 'D': 0}
        prow = [0] * (m + 1)
        pcol = [0] * (m + 1)
        for i, ch in enumerate(s):
            prow[i + 1] = prow[i] + dr[ch]
            pcol[i + 1] = pcol[i] + dc[ch]
        res = [0] * m
        for i in range(m):
            cnt = 0
            for j in range(i, m):
                row_abs = startPos[0] + prow[j + 1] - prow[i]
                col_abs = startPos[1] + pcol[j + 1] - pcol[i]
                if 0 <= row_abs < n and 0 <= col_abs < n:
                    cnt += 1
                else:
                    break
            res[i] = cnt
        return res

