class Solution:
    def executeInstructions(self, n, startPos, s):
        m = len(s)
        dirs = {'L': (0, -1), 'R': (0, 1), 'U': (-1, 0), 'D': (1, 0)}
        res = [0] * m
        for i in range(m):
            r, c = startPos[0], startPos[1]
            cnt = 0
            for j in range(i, m):
                dr, dc = dirs[s[j]]
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n:
                    r, c = nr, nc
                    cnt += 1
                else:
                    break
            res[i] = cnt
        return res

